def max_Prime_Factors(n):
    def is_prime(num):
        if num <= 1:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True

    largest_factor = -1
    # Check divisibility starting from the square root of n and moving downwards
    for i in range(int(n**0.5), 1, -1):
        if n % i == 0 and is_prime(i):
            largest_factor = max(largest_factor, i)
            break  # The first prime factor found will be the largest one

    return largest_factor
```

