def eulerian_num(n, m):
    if n == 0 and m == 0:
        return 1
    elif n < 0 or m < 0:
        return 0
    else:
        # Recursive calculation of Eulerian number
        return (n * eulerian_num(n - 1, (m + 1) % 2) +
                (m + 1) * eulerian_num(n - 1, m % 2))
```

