def comb_sort(arr):
    def gap_adjust(gap):
        if gap == 1:
            return False
        return gap // 1.3

    swapped = True

    gap = len(arr)
    shrink_factor = 1.3

    while not swapped or gap > 1:
        gap = max(1, int(gap / shrink_factor))
        swapped = False
        for i in range(len(arr) - gap):
            if arr[i] > arr[i + gap]:
                arr[i], arr[i + gap] = arr[i + gap], arr[i]
                swapped = True
    return arr
```

