def maximum_Sum(matrix):
    if not matrix or not matrix[0]:
        return 0

    max_sum = float('-inf')
    rows, cols = len(matrix), len(matrix[0])

    for i in range(rows):
        for j in range(cols):
            current_max = max(max_sum, sum(matrix[k][j] for k in range(rows) if k != i))
            max_sum = max(max_sum, matrix[i][j] + current_max)

    return max_sum
```

