def count_substrings(s: str) -> int:
    def is_valid(sub):
        return len(sub) == sum(int(digit) for digit in sub)

    count = 0
    n = len(s)
    for i in range(n):
        for j in range(i, n):
            substring = s[i:j+1]
            if is_valid(substring):
                count += 1
    return count
```

